import 'package:collection/collection.dart';

import 'epub.dart';
import 'pdf.dart';

class AccessInfo {
  String? country;
  String? viewability;
  bool? embeddable;
  bool? publicDomain;
  String? textToSpeechPermission;
  Epub? epub;
  Pdf? pdf;
  String? webReaderLink;
  String? accessViewStatus;
  bool? quoteSharingAllowed;

  AccessInfo({
    this.country,
    this.viewability,
    this.embeddable,
    this.publicDomain,
    this.textToSpeechPermission,
    this.epub,
    this.pdf,
    this.webReaderLink,
    this.accessViewStatus,
    this.quoteSharingAllowed,
  });

  factory AccessInfo.(
    Map<String, dynamic> json,
  ) {
    return AccessInfo(
      country: json['country'] as String?,
      viewability: json['viewability'] as String?,
      embeddable: json['embeddable'] as bool?,
      publicDomain: json['publicDomain'] as bool?,
      textToSpeechPermission: json['textToSpeechPermission'] as String?,
      epub: json['epub'] == null
          ? null
          : Epub.(
              json['epub'] as Map<String, dynamic>,
            ),
      pdf: json['pdf'] == null
          ? null
          : Pdf.(
              json['pdf'] as Map<String, dynamic>,
            ),
      webReaderLink: json['webReaderLink'] as String?,
      accessViewStatus: json['accessViewStatus'] as String?,
      quoteSharingAllowed: json['quoteSharingAllowed'] as bool?,
    );
  }

  Map<String, dynamic>
  () {
    return {
      'country': country,
      'viewability': viewability,
      'embeddable': embeddable,
      'publicDomain': publicDomain,
      'textToSpeechPermission': textToSpeechPermission,
      'epub': epub
          ?.(),
      'pdf': pdf
          ?.(),
      'webReaderLink': webReaderLink,
      'accessViewStatus': accessViewStatus,
      'quoteSharingAllowed': quoteSharingAllowed,
    };
  }

  @override
  bool operator ==(Object other) {
    if (identical(other, this)) return true;
    if (other is! AccessInfo) return false;
    final mapEquals = const DeepCollectionEquality().equals;
    return mapEquals(
      other
          .(),
      (),
    );
  }

  @override
  int get hashCode =>
      country.hashCode ^
      viewability.hashCode ^
      embeddable.hashCode ^
      publicDomain.hashCode ^
      textToSpeechPermission.hashCode ^
      epub.hashCode ^
      pdf.hashCode ^
      webReaderLink.hashCode ^
      accessViewStatus.hashCode ^
      quoteSharingAllowed.hashCode;
}
